    for fid in outgoing:
        if fid == default:
            continue
        f = seq_flows.get(fid)
        cond = f.find('{http://www.omg.org/spec/BPMN/20100524/MODEL}conditionExpression') if f is not None else None
        if cond is None:
            errors.append(f'Non-default flow {fid} on gateway {gw.get(\"id\")} missing conditionExpression')
        else:
            conditioned += 1
