python3 -c "
import xml.etree.ElementTree as ET

tree = ET.parse('/work/output/artifacts/skill-bpmn-switch/SeasonLookup.bpmn')
root = tree.getroot()

ns = {
    'bpmn': 'http://www.omg.org/spec/BPMN/20100524/MODEL',
    'bpmndi': 'http://www.omg.org/spec/BPMN/20100524/DI',
}

errors = []

# 1. Root is definitions with required namespaces (ElementTree expands ns in tag)
assert '{http://www.omg.org/spec/BPMN/20100524/MODEL}definitions' == root.tag, f'Root tag wrong: {root.tag}'

# 2. One BPMNDiagram
diagrams = root.findall('bpmndi:BPMNDiagram', ns)
if len(diagrams) != 1:
    errors.append(f'Expected 1 BPMNDiagram, found {len(diagrams)}')

# Collect all element ids
ids = {el.get('id') for el in root.iter() if el.get('id')}

proc = root.find('bpmn:process', ns)
flow_nodes = [el for el in proc if el.get('id') and 'sequenceFlow' not in el.tag and 'extensionElements' not in el.tag]
flow_node_ids = {el.get('id') for el in flow_nodes}
seq_flows = {el.get('id'): el for el in proc if 'sequenceFlow' in el.tag}

# Check all sourceRef/targetRef resolve
for fid, f in seq_flows.items():
    src = f.get('sourceRef'); tgt = f.get('targetRef')
    if src not in ids: errors.append(f'Flow {fid} sourceRef {src} missing')
    if tgt not in ids: errors.append(f'Flow {fid} targetRef {tgt} missing')

# 3. BPMNShape per node, BPMNEdge per flow
plane = diagrams[0].find('bpmndi:BPMNPlane', ns)
shapes = {s.get('bpmnElement') for s in plane.findall('bpmndi:BPMNShape', ns)}
edges  = {e.get('bpmnElement') for e in plane.findall('bpmndi:BPMNEdge', ns)}

for nid in flow_node_ids:
    if nid not in shapes:
        errors.append(f'Node {nid} has no BPMNShape')
for fid in seq_flows:
    if fid not in edges:
        errors.append(f'Flow {fid} has no BPMNEdge')

# 4. XOR gateway: non-default flows have conditions; exactly one default
for gw in proc.findall('bpmn:exclusiveGateway', ns):
    default = gw.get('default')
    outgoing = [sf.text.strip() for sf in gw.findall('bpmn:outgoing', ns)]
    if not default:
        errors.append(f'Gateway {gw.get(\"id\")} has no default')
    else:
        if default not in seq_flows:
            errors.append(f'Gateway {gw.get(\"id\")} default {default} not a known flow')
    conditioned = 0
    for fid in outgoing:
        if fid == default:
            continue
        f = seq_flows.get(fid)
        cond = f.find('{http://www.omg.org/spec/BPMN/20100524/MODEL}conditionExpression') if f is not None else None
        if cond is None:
            errors.append(f'Non-default flow {fid} missing conditionExpression')
        else:
            conditioned += 1
    if conditioned < 3:
        errors.append(f'Gateway {gw.get(\"id\")} has only {conditioned} conditioned branches (need >= 3)')

# 5. No activity/event with > 1 incoming (gateways may have many)
for el in flow_nodes:
    inc = el.findall('bpmn:incoming', ns)
    if len(inc) > 1 and 'Gateway' not in el.tag and 'SubProcess' not in el.tag:
        errors.append(f'Element {el.get(\"id\")} has {len(inc)} incoming flows')

print('flow_nodes:', [el.get('id') for el in flow_nodes])
print('seq_flows:', list(seq_flows.keys()))
print('shapes:', sorted(shapes))
print('edges:', sorted(edges))

if errors:
    print('ERRORS:')
    for e in errors: print(' -', e)
else:
    print('VALID - all structural checks passed')
"
